const testAuthConfigUpdateEndpointID = "projects.config.update-auth-service"

func TestCodeOrchExecuteRedactsAuthConfig(t *testing.T) {
	const sentinel = "synthetic-credential-must-not-escape"
	t.Setenv("HOME", t.TempDir())
	t.Setenv("SUPABASE_ACCESS_TOKEN", "synthetic-management-token")
	server := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		_, _ = w.Write([]byte(`{
			"site_url":"https://portal.example.test",
			"external_google_secret":"synthetic-credential-must-not-escape-google",
			"smtp_pass":"synthetic-credential-must-not-escape-smtp"
		}`))
	}))
	defer server.Close()
	t.Setenv("SUPABASE_BASE_URL", server.URL)

	result, err := handleCodeOrchExecute(context.Background(), mcplib.CallToolRequest{
		Params: mcplib.CallToolParams{Arguments: map[string]any{
			"endpoint_id": "projects.config.get-auth-service",
			"params":      map[string]any{"ref": "project-ref"},
		}},
	})
	if err != nil {
		t.Fatal(err)
	}
	if result.IsError {
		t.Fatalf("MCP result is an error: %#v", result.Content)
	}
	text, ok := result.Content[0].(mcplib.TextContent)
	if !ok {
		t.Fatalf("MCP content type = %T, want TextContent", result.Content[0])
	}
	if strings.Contains(text.Text, sentinel) {
		t.Fatalf("MCP output leaked a credential sentinel: %s", text.Text)
	}
	if !strings.Contains(text.Text, "portal.example.test") {
		t.Fatalf("MCP output omitted approved metadata: %s", text.Text)
	}
}

func TestCodeOrchSearchOmitsCredentialBearingAuthConfigUpdate(t *testing.T) {
	result, err := handleCodeOrchSearch(context.Background(), mcplib.CallToolRequest{
		Params: mcplib.CallToolParams{Arguments: map[string]any{
			"query": "update auth service config",
			"limit": float64(200),
		}},
	})
	if err != nil {
		t.Fatal(err)
	}
	if result.IsError {
		t.Fatalf("MCP search returned an error: %#v", result.Content)
	}
	text, ok := result.Content[0].(mcplib.TextContent)
	if !ok {
		t.Fatalf("MCP content type = %T, want TextContent", result.Content[0])
	}
	if strings.Contains(text.Text, testAuthConfigUpdateEndpointID) {
		t.Fatalf("MCP search advertised denied credential-bearing endpoint: %s", text.Text)
	}
}

func TestCodeOrchExecuteDeniesCredentialBearingAuthConfigUpdateWithoutEcho(t *testing.T) {
	const sentinel = "synthetic-credential-must-not-escape"
	result, err := handleCodeOrchExecute(context.Background(), mcplib.CallToolRequest{
		Params: mcplib.CallToolParams{Arguments: map[string]any{
			"endpoint_id": testAuthConfigUpdateEndpointID,
			"params": map[string]any{
				"ref":                    "project-ref",
				"external_google_secret": sentinel,
			},
		}},
	})
	if err != nil {
		t.Fatal(err)
	}
	if !result.IsError {
		t.Fatalf("credential-bearing MCP update was not denied: %#v", result.Content)
	}
	text, ok := result.Content[0].(mcplib.TextContent)
	if !ok {
		t.Fatalf("MCP content type = %T, want TextContent", result.Content[0])
	}
	if strings.Contains(text.Text, sentinel) {
		t.Fatalf("MCP denial echoed a credential sentinel: %s", text.Text)
	}
	if !strings.Contains(text.Text, "--stdin") {
		t.Fatalf("MCP denial omitted safe CLI guidance: %s", text.Text)
	}
}

func TestCredentialBearingCodeOrchEndpointPolicyDerivesFromMethodAndPath(t *testing.T) {
	for _, testCase := range []struct {
		name string
		ep   codeOrchEndpoint
		want bool
	}{
		{name: "auth config read remains available", ep: codeOrchEndpoint{Method: http.MethodGet, Path: "/v1/projects/{ref}/config/auth"}},
		{name: "current auth config update denied", ep: codeOrchEndpoint{Method: http.MethodPatch, Path: "/v1/projects/{ref}/config/auth"}, want: true},
		{name: "future auth config write denied", ep: codeOrchEndpoint{Method: http.MethodPost, Path: "/v1/projects/{ref}/config/auth"}, want: true},
		{name: "unrelated config write remains available", ep: codeOrchEndpoint{Method: http.MethodPatch, Path: "/v1/projects/{ref}/config/database"}},
	} {
		t.Run(testCase.name, func(t *testing.T) {
			if got := isCredentialBearingCodeOrchEndpoint(&testCase.ep); got != testCase.want {
				t.Fatalf("isCredentialBearingCodeOrchEndpoint() = %t, want %t", got, testCase.want)
			}
		})
	}
}

// TestValidateReadOnlyQuery_AllowsSelectAndWITH pins the contract: the MCP
// sql tool's allowlist accepts SELECT and WITH-prefix queries, including
// CTEs, mixed case, leading whitespace, leading SQL comments, and leading
// statement separators. SELECT-form CTEs ("WITH x AS (SELECT ...) SELECT")
// must work because novel CLI sql commands in the public library accept
// them as legitimate read-only queries; the MCP surface keeps parity.
func TestValidateReadOnlyQuery_AllowsSelectAndWITH(t *testing.T) {
	allowed := []string{
		"SELECT 1",
		"select * from resources",
		"  SELECT 1",
		"\tSELECT 1",
		"\nSELECT 1",
		";SELECT 1",
		"-- comment\nSELECT 1",
		"/* comment */ SELECT 1",
		"/* comment */SELECT 1",
		"/**/SELECT 1",
		"-- one\n-- two\nSELECT 1",
		"/* a *//* b */ SELECT 1",
		"WITH r AS (SELECT 1) SELECT * FROM r",
		"with r as (select 1) select * from r",
	}
	for _, q := range allowed {
		if err := validateReadOnlyQuery(q); err != nil {
			t.Errorf("validateReadOnlyQuery(%q) = %v, want nil", q, err)
		}
	}
}

// TestValidateReadOnlyQuery_RejectsBypassVectors covers the comment-prefix
// bypass class that defeated the earlier prefix-blocklist gate. mode=ro on
// modernc.org/sqlite does not block VACUUM INTO (writes a fresh file) or
// ATTACH DATABASE (opens a separate writable handle), so the gate is the
// only defense against those vectors. A successful bypass at this layer
// would let an MCP-trusting agent silently exfiltrate the local database.
func TestValidateReadOnlyQuery_RejectsBypassVectors(t *testing.T) {
	rejected := []string{
		"VACUUM INTO '/tmp/x.db'",
		"ATTACH DATABASE 'file:/tmp/x.db?mode=rwc' AS evil",
		"INSERT INTO resources VALUES ('x', 'y', '{}')",
		"UPDATE resources SET resource_type = 'evil'",
		"DELETE FROM resources",
		"REPLACE INTO resources VALUES ('seed', 'evil', '{}')",
		"DROP TABLE resources",
		"PRAGMA writable_schema = ON",
		"REINDEX",
		"DETACH DATABASE x",
		"/* x */ VACUUM INTO '/tmp/exfil.db'",
		"/* x */VACUUM INTO '/tmp/exfil.db'",
		"-- x\nVACUUM INTO '/tmp/exfil.db'",
		"/**/VACUUM INTO '/tmp/exfil.db'",
		"/* x */ ATTACH DATABASE 'file:/tmp/x.db?mode=rwc' AS evil",
		"-- x\nATTACH DATABASE '/tmp/x.db' AS evil",
		";VACUUM INTO '/tmp/x.db'",
		"; ; VACUUM INTO '/tmp/x.db'",
		"/* a */ /* b */ INSERT INTO t VALUES (1)",
		"/* outer /* not nested */ */ SELECT 1", // SQLite doesn't nest, so trailing "*/" closes; second SELECT remains. Reject — the gate must err on the side of caution when the leading shape is suspicious.
		"-- only a comment",
		"/* only a comment */",
		"",
		"   ",
		";",
	}
	for _, q := range rejected {
		if err := validateReadOnlyQuery(q); err == nil {
			t.Errorf("validateReadOnlyQuery(%q) = nil, want error", q)
		}
	}
}

// TestStripLeadingSQLNoise checks the helper directly so a regression in the
// stripping logic (off-by-one on /* */ length, missing newline handling on
// --) surfaces close to the source rather than only via the integration
// behavior of validateReadOnlyQuery.
func TestStripLeadingSQLNoise(t *testing.T) {
	cases := []struct {
		in, want string
	}{
		{"SELECT 1", "SELECT 1"},
		{"  SELECT 1", "SELECT 1"},
		{"\t\nSELECT 1", "SELECT 1"},
		{";SELECT 1", "SELECT 1"},
		{";; ;SELECT 1", "SELECT 1"},
		{"-- x\nSELECT 1", "SELECT 1"},
		{"-- x\n-- y\nSELECT 1", "SELECT 1"},
		{"/* x */SELECT 1", "SELECT 1"},
		{"/**/SELECT 1", "SELECT 1"},
		{"/* x */ /* y */ SELECT 1", "SELECT 1"},
		{"-- only", ""},
		{"/* only", ""},
		{"", ""},
	}
	for _, c := range cases {
		got := stripLeadingSQLNoise(c.in)
		if !strings.EqualFold(got, c.want) {
			t.Errorf("stripLeadingSQLNoise(%q) = %q, want %q", c.in, got, c.want)
		}
	}
}
